const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const errors = [];

// Company
if (!item.json.companyName?.trim()) {
  errors.push("Company Name is missing");
}

// Contact Name
if (!item.json.contactName?.trim()) {
  errors.push("Contact Name is missing");
}

// Email
if (!item.json.email?.trim()) {
  errors.push("Business Email is missing");
}
else if (!emailRegex.test(item.json.email)) {
  errors.push("Business Email format is invalid");
}

// Training
const validCourses = [
  "Product Basics",
  "CMS Fundamentals",
  "API Integration",
  "Experimentation",
  "Commerce Platform"
];

if (!validCourses.includes(item.json.trainingProgram)) {
  errors.push("Invalid Training Program");
}

// Country
if (!item.json.country?.trim()) {
  errors.push("Country is missing");
}

// Final Result
item.json.validationPassed = errors.length === 0;
item.json.validationErrors = errors;
item.json.validationStatus = errors.length === 0 ? "Passed" : "Failed";

return item;

// Was the validation successful?
const validationPassed = item.json.validationPassed;

// Did HubSpot return an existing contact?
const hubspotExists = !!item.json.id;

// Decide what should happen next.
let action = "";
let reason = "";

if (!validationPassed) {
  action = "STOP";
  reason = "Validation Failed";
} else if (hubspotExists) {
  action = "UPDATE_CONTACT";
  reason = "Existing HubSpot Contact";
} else {
  action = "CREATE_CONTACT";
  reason = "New Partner";
}

item.json.nextAction = action;
item.json.decisionReason = reason;

return item;
